    private fun ASTNode.isPartOfAnnotatedExpression(): Boolean {
        var currentNode: ASTNode? = this
        while (currentNode != null) {
            if (currentNode.elementType == ANNOTATED_EXPRESSION || currentNode.elementType == ANNOTATION_ENTRY) {
                return true
            }
            currentNode = currentNode.treeParent
        }
        return false
    }

    private fun isMaxLineLengthSet() = maxLineLength != MAX_LINE_LENGTH_PROPERTY_OFF
